member.example:
Bind the Selectable interactable property using a serialized binder field — the target Selectable is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private SelectableInteractableBinder _interactable;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _interactable;
    }


Bind the Selectable interactable property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Selectable _selectable;
        
        private SelectableInteractableBinder Interactable =>
            new(_selectable);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _interactable;
    }
